    constructor(props) {
        super(props);
        this.state = {
            files: []
        };

        this.handleAttachFile = this.handleAttachFile.bind(this);
    }

    handleAttachFile(e) {
        console.log(e.target.files);

    }

    render() {


        return (
            <>
                <input type="file" multiple onChange={this.handleAttachFile}/>
